"""Invariant Inspector

A LOOP INVARIANT is a statement about a program's variables that is (1) true right before the loop starts, (2) preserved by every single iteration -- if it was true before an iteration, it is still true after that iteration runs -- and (3) combined with the loop's EXIT CONDITION (the thing that becomes false and stops the loop), gives you the POSTCONDITION -- what you actually know is true once the loop is done. This is the informal, engineering version of a loop invariant: not a formal proof, just a disciplined habit of naming 'what stays true here, every single time control passes through this point' so you can trust a loop's correctness by inspection instead of by guessing. Each question here shows a small, real loop and asks which enumerated statement IS the loop invariant, versus a statement that only happens to be true sometimes, or is really the postcondition in disguise.
"""
import json, sys

# -- Crypto / obfuscation --
_KEY_A = "580440040eefd9906ff9f01e542aeac6466c88b7b2eadd4fb94e42490bbeb964"
_KEY_B = "03b0a6912b975af1da603c696611993d3549b7f599615a62e6a04fee943ef200"
import base64 as _b64, hashlib as _hl, hmac as _hm, json as _js, zlib as _zl

_SALT      = bytes.fromhex("a3f1b2c4d5e6f7a8b9c0d1e2f3a4b5c6")
_KDF_ITERS = 100000

# Split runtime key. This is obfuscation only; do not treat it as a secret.
def _xor_bytes(a, b):
    return bytes(x ^ y for x, y in zip(a, b))

def _runtime_key():
    return _xor_bytes(bytes.fromhex(_KEY_A), bytes.fromhex(_KEY_B))

def _derive_key(answers):
    return _hl.pbkdf2_hmac("sha256", "|".join(answers).encode(), _SALT, _KDF_ITERS)

def _stream(key, length):
    ks, i = b"", 0
    while len(ks) < length:
        ks += _hl.sha256(key + i.to_bytes(4, "little")).digest()
        i += 1
    return ks[:length]

def _decrypt(blob_hex, answers):
    blob    = bytes.fromhex(blob_hex)
    key     = _derive_key(answers)
    ct, mac = blob[:-32], blob[-32:]
    if not _hm.compare_digest(mac, _hm.new(key, ct, _hl.sha256).digest()):
        return None
    return bytes(a ^ b for a, b in zip(ct, _stream(key, len(ct)))).decode()

def _item_key(label):
    return _hm.new(_runtime_key(), label.encode(), _hl.sha256).digest()

def _open_secret(blob_text, label):
    try:
        blob = _b64.b85decode(blob_text.encode())
        key = _item_key(label)
        ct, mac = blob[:-32], blob[-32:]
        if not _hm.compare_digest(mac, _hm.new(key, ct, _hl.sha256).digest()):
            return None
        pt = _xor_bytes(ct, _stream(key, len(ct)))
        data = _js.loads(_zl.decompress(pt).decode())
        return data if isinstance(data, dict) else None
    except Exception:
        return None

